function solve(nums, queries) {
    const MOD = 10**9 + 7;
    const n = nums.length;
    const multiplyCount = new Array(n).fill(0);

    for (const [li, ri, ki, vi] of queries) {
        let idx = li;
        while (idx <= ri) {
            multiplyCount[idx] += 1;
            idx += ki;
        }
    }

    let result = 0;
    for (let i = 0; i < n; i++) {
        let val = nums[i];
        for (let j = 0; j < multiplyCount[i]; j++) {
            val = (val * vi) % MOD;
        }
        result ^= val;
    }

    return result;
}
